import React from "react";
import Link from "gatsby-link";
import Helmet from "react-helmet";

import "../css/styles.css";

const featuredWork = [
  {
    title: "Front-end systems",
    description:
      "Interface work that blends thoughtful structure, responsive layouts, and the details that make products easier to use.",
    meta: "React, CSS, SVG",
    url: "/snippets/"
  },
  {
    title: "Writing and demos",
    description:
      "Older articles and experiments on SVG, prototyping, form optimization, and building better web experiences.",
    meta: "Articles, CodePen, talks",
    url: "/posts/"
  },
  {
    title: "Calligraphy practice",
    description:
      "A creative archive that keeps the site from being only code. Letterforms, rhythm, and craft all show up in interface work too.",
    meta: "Visual practice",
    url: "/calligraphy/"
  }
];

const Index = () => (
  <main className="home">
    <Helmet
      title="Quinton Jason | Front-end Developer"
      meta={[
        {
          name: "description",
          content:
            "Quinton Jason is a front-end developer who builds thoughtful web interfaces, writes about the web, and experiments with visual craft."
        }
      ]}
    />
    <section className="home-hero">
      <div className="container home-hero__inner">
        <p className="home-hero__eyebrow">Front-end developer and maker</p>
        <h1 className="home-hero__title">Quinton Jason</h1>
        <p className="home-hero__bio">
          I build thoughtful web interfaces, write about the craft of front-end
          development, and keep a creative practice that connects code, motion,
          and design.
        </p>
        <div className="home-hero__actions">
          <Link to="/snippets/" className="button button--primary">
            View snippets
          </Link>
          <Link to="/posts/" className="button button--secondary">
            Read writing
          </Link>
        </div>
      </div>
    </section>

    <section className="home-section">
      <div className="container">
        <div className="section-heading">
          <p className="section-heading__eyebrow">Selected paths</p>
          <h2>Work, writing, and visual practice</h2>
        </div>
        <div className="work-grid">
          {featuredWork.map(item => (
            <Link to={item.url} className="work-card" key={item.title}>
              <span className="work-card__meta">{item.meta}</span>
              <h3>{item.title}</h3>
              <p>{item.description}</p>
            </Link>
          ))}
        </div>
      </div>
    </section>

    <section className="home-section home-section--quiet">
      <div className="container home-note">
        <div>
          <p className="section-heading__eyebrow">Now</p>
          <h2>Rebuilding the archive into a current portfolio.</h2>
        </div>
        <p>
          This site has years of experiments and writing behind it. The next
          version brings the strongest pieces forward, keeps the old archive
          useful, and makes it easier to understand what I care about today.
        </p>
        <Link to="/contact/" className="text-link">
          Get in touch
        </Link>
      </div>
    </section>
  </main>
);

export default Index;



